  const q = String($json.query || '').toLowerCase();
  let seed = [];
  try {
    const raw = String($('Webhook').item.json.body?.keyword || $('Webhook').item.json.keyword || '').toLowerCase().trim();
    if (raw) seed.push(raw);
  } catch(e) {
    try {
      seed = $('List Focus Keyword').all().map(i => String(i.json.keyword || '').toLowerCase().trim()).filter(Boolean);
    } catch(err) {
      seed = [];
    }
  }
  const stopWords = new Set(['di', 'ke', 'dari', 'yang', 'dan', 'untuk', 'dengan', 'ada', 'adalah', 'itu', 'ini', 'makanan', 'kuliner', 'minuman', 'resep', 'cara', 'tips', 'info']);
  const terms = [];
  seed.forEach(phrase => {
    terms.push(phrase);
    phrase.split(/\s+/).forEach(word => {
      const clean = word.replace(/[^a-z0-9]/g, '');
      if (clean.length > 2 && !stopWords.has(clean)) {
        terms.push(clean);
      }
    });
  });
  const uniqueTerms = [...new Set(terms)].filter(Boolean);
  const esc = s => s.replace(/[.*+?^$\{\}()|[\]\\]/g, '\\$&');
  return uniqueTerms.some(t => {
    if (t.includes(' ')) {
      return q.includes(t);
    } else {
      return new RegExp('\\b' + esc(t) + '\\b', 'i').test(q);
    }
  });
})() }}

