// Extract input JSON (which is the output from AI Agent / Basic LLM Chain)
const aiInput = $json;

// Get Client Info from Webhook safely without relying on item pairing
let clientInfo = {};
try {
  const webhookData = $('Webhook').first().json;
  clientInfo = webhookData.body || webhookData;
} catch (err) {
  clientInfo = aiInput.body || aiInput;
}

// Safe parse JSON from AI response
function safeParseJson(str) {
  if (!str) return null;
  if (typeof str === 'object') return str;
  try {
    const clean = str.replace(/```json/gi,"").replace(/```/g,"").trim();
    const start = clean.indexOf('{');
    const end = clean.lastIndexOf('}');
    if (start === -1 || end === -1) {
      return JSON.parse(clean);
    }
    return JSON.parse(clean.slice(start, end + 1));
  } catch (e) {
    try {
      return JSON.parse(str);
    } catch (err2) {
      return null;
    }
  }
}

const text = aiInput.text || aiInput.output || '';
const parsed = safeParseJson(text) || safeParseJson(aiInput);

const kw = clientInfo.keyword || clientInfo.query || "Keyword Utama";

// Get search metrics safely without relying on item pairing
let searchVolume = 0;
let difficulty = 0;
try {
  const svNode = $('Riset SVolume').first().json;
  searchVolume = svNode.data?.globalSearchVolume || 0;
  difficulty = svNode.data?.difficulty || 0;
} catch (e) {
  // Riset SVolume was not executed or failed
}

return [{
  json: {
    clientName: clientInfo.Client_Name || "Supermat Client",
    projectId: clientInfo.projectId || clientInfo.sanityProjectId || "mwwvwgiw",
    studioUrl: clientInfo.studioUrl || "",
    telegramChatId: clientInfo.Telegram_Chat_ID || "",
    cmsType: (clientInfo.CMS_Type || "sanity").toLowerCase().trim(),
    article: {
      title: parsed?.title || "Draft Article",
      slug: parsed?.slug || "draft-article",
      excerpt: parsed?.excerpt || "",
      bodyMarkdown: parsed?.body || "",
      keywords: [kw],
      primaryKeyword: kw,
      searchVolume: searchVolume,
      difficulty: difficulty
    }
  }
}];

const body = $json.body || {};
return [{
  json: {
    clientName: body.clientName || "Supermat Client",
    projectId: body.projectId || "mwwvwgiw",
    telegramChatId: body.telegramChatId || "",
    cmsType: (body.cmsType || "sanity").toLowerCase().trim(),
    article: body.article || null,
    authToken: body.authToken || "",
    draftDocId: body.draftDocId || "" // <--- PASTIKAN BARIS INI ADA
  }
}];
